#include <iostream>
#include <vector>

using namespace std;

int find_nth_number(int n) {
    if (n == 0) return 0;
    if (n == 1) return -1;
    if (n == 2) return -1;

    vector<int> sequence = {0, -1, -1};
    for (int i = 3; i <= n; ++i) {
        int next_number = sequence[i - 1] + sequence[i - 2] + sequence[i - 3];
        sequence.push_back(next_number);
    }
    return sequence[n];
}

int main() {
    int n;
    cout << "Enter the index of the sequence: ";
    cin >> n;
    cout << "The " << n << "th number in the sequence is: " << find_nth_number(n) << endl;
    return 0;
}
```

